import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import '../styles/MedicationDiary.css';

function MedicationDiary() {
  const navigate = useNavigate();
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [currentDate, setCurrentDate] = useState(new Date());
  const [selectedDate, setSelectedDate] = useState(null);
  const [medications, setMedications] = useState([]);
  const [medicationSchedule, setMedicationSchedule] = useState({});
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalMode, setModalMode] = useState('add'); // 'add' or 'edit'
  const [selectedMedication, setSelectedMedication] = useState(null);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  // Form data for adding/editing medications
  const [formData, setFormData] = useState({
    medication_id: '',
    dose: '',
    time_slot: 'morning',
    comment: '',
    date: new Date().toISOString().split('T')[0]
  });

  // Predefined medication list (in a real app, this would come from API)
  const availableMedications = [
    { id: 1, name: 'Salbutamol (Ventolin)', type: 'Inhaler' },
    { id: 2, name: 'Fluticasone (Flixotide)', type: 'Corticosteroid' },
    { id: 3, name: 'Montelukast (Singulair)', type: 'Leukotriene modifier' },
    { id: 4, name: 'Budesonide/Formoterol (Symbicort)', type: 'Combination inhaler' },
    { id: 5, name: 'Cetirizine', type: 'Antihistamine' }
  ];

  // Sample data structure for medication schedules
  // In a real app, these would be fetched from an API
  useEffect(() => {
    const user_id = localStorage.getItem('user_id');
    if (!user_id) {
      navigate('/');
      return;
    }

    // Mock data for medication schedules
    const mockMedicationSchedules = {
      '2023-10-01': [
        { id: 1, medication_id: 1, name: 'Salbutamol', dose: '100 mcg', time_slot: 'morning', taken: true },
        { id: 2, medication_id: 3, name: 'Montelukast', dose: '10 mg', time_slot: 'evening', taken: false }
      ],
      '2023-10-02': [
        { id: 3, medication_id: 1, name: 'Salbutamol', dose: '100 mcg', time_slot: 'morning', taken: true },
        { id: 4, medication_id: 2, name: 'Fluticasone', dose: '250 mcg', time_slot: 'evening', taken: true }
      ],
      // Add more dates with medication schedules as needed
    };

    setMedicationSchedule(mockMedicationSchedules);
    setMedications(availableMedications);

    // In a real app, you would fetch data from an API here
    // Example:
    // fetchMedicationSchedules(user_id);
    // fetchMedicationList();
  }, [navigate]);

  const handleLogout = () => {
    localStorage.removeItem('user_id');
    navigate('/');
  };

  const toggleSidebar = () => {
    setIsSidebarOpen(!isSidebarOpen);
  };

  // Calendar navigation functions
  const previousMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() - 1, 1));
  };

  const nextMonth = () => {
    setCurrentDate(new Date(currentDate.getFullYear(), currentDate.getMonth() + 1, 1));
  };

  // Generate calendar days
  const generateCalendarDays = () => {
    const year = currentDate.getFullYear();
    const month = currentDate.getMonth();
    
    // Get first day of the month
    const firstDay = new Date(year, month, 1);
    // Get last day of the month
    const lastDay = new Date(year, month + 1, 0);
    
    const daysArray = [];
    let currentDay = new Date(firstDay);
    
    // Add days from previous month to align with correct weekday
    const startingDayOfWeek = firstDay.getDay(); // 0 is Sunday, 1 is Monday, etc.
    if (startingDayOfWeek !== 0) {
      const lastDayPrevMonth = new Date(year, month, 0);
      const daysInPrevMonth = lastDayPrevMonth.getDate();
      
      for (let i = startingDayOfWeek - 1; i >= 0; i--) {
        const day = new Date(year, month - 1, daysInPrevMonth - i);
        daysArray.push({
          date: day,
          isCurrentMonth: false,
          hasSchedule: medicationSchedule[day.toISOString().split('T')[0]] ? true : false
        });
      }
    }
    
    // Add days of current month
    while (currentDay <= lastDay) {
      const dateString = currentDay.toISOString().split('T')[0];
      daysArray.push({
        date: new Date(currentDay),
        isCurrentMonth: true,
        hasSchedule: medicationSchedule[dateString] ? true : false
      });
      currentDay.setDate(currentDay.getDate() + 1);
    }
    
    // Add days from next month to complete the grid (if needed)
    const remainingDays = 42 - daysArray.length; // 6 rows of 7 days
    if (remainingDays > 0) {
      for (let i = 1; i <= remainingDays; i++) {
        const day = new Date(year, month + 1, i);
        daysArray.push({
          date: day,
          isCurrentMonth: false,
          hasSchedule: medicationSchedule[day.toISOString().split('T')[0]] ? true : false
        });
      }
    }
    
    return daysArray;
  };

  // Open modal for adding/editing medication
  const openAddMedicationModal = (date) => {
    setSelectedDate(date);
    setFormData({...formData, date: date.toISOString().split('T')[0]});
    setModalMode('add');
    setIsModalOpen(true);
  };

  const openEditMedicationModal = (medication) => {
    setSelectedMedication(medication);
    setFormData({
      medication_id: medication.medication_id,
      dose: medication.dose,
      time_slot: medication.time_slot,
      comment: medication.comment || '',
      date: selectedDate.toISOString().split('T')[0]
    });
    setModalMode('edit');
    setIsModalOpen(true);
  };

  // Close modal
  const closeModal = () => {
    setIsModalOpen(false);
    setSelectedMedication(null);
    setFormData({
      medication_id: '',
      dose: '',
      time_slot: 'morning',
      comment: '',
      date: new Date().toISOString().split('T')[0]
    });
  };

  // Handle form input changes
  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData({
      ...formData,
      [name]: value
    });
  };

  // Handle form submission for adding/editing medication
  const handleSubmitMedication = (e) => {
    e.preventDefault();
    
    if (!formData.medication_id || !formData.dose) {
      setError('Please select a medication and specify the dose');
      return;
    }

    // In a real app, you would send this data to an API
    // For now, we'll update the local state
    
    const selectedMedicationInfo = medications.find(med => med.id === parseInt(formData.medication_id));
    
    if (modalMode === 'add') {
      // Create a new medication schedule entry
      const newSchedule = {
        ...medicationSchedule
      };
      
      const newMedication = {
        id: Date.now(), // Use timestamp as temp ID, would be set by backend in real app
        medication_id: parseInt(formData.medication_id),
        name: selectedMedicationInfo.name,
        dose: formData.dose,
        time_slot: formData.time_slot,
        taken: false,
        comment: formData.comment
      };
      
      if (newSchedule[formData.date]) {
        newSchedule[formData.date] = [...newSchedule[formData.date], newMedication];
      } else {
        newSchedule[formData.date] = [newMedication];
      }
      
      setMedicationSchedule(newSchedule);
      setSuccess('Medication added to schedule');
    } else if (modalMode === 'edit' && selectedMedication) {
      // Update existing medication schedule
      const updatedSchedule = {
        ...medicationSchedule
      };
      
      const dateKey = selectedDate.toISOString().split('T')[0];
      
      if (updatedSchedule[dateKey]) {
        updatedSchedule[dateKey] = updatedSchedule[dateKey].map(med => {
          if (med.id === selectedMedication.id) {
            return {
              ...med,
              medication_id: parseInt(formData.medication_id),
              name: selectedMedicationInfo.name,
              dose: formData.dose,
              time_slot: formData.time_slot,
              comment: formData.comment
            };
          }
          return med;
        });
      }
      
      setMedicationSchedule(updatedSchedule);
      setSuccess('Medication schedule updated');
    }
    
    closeModal();
  };

  // Toggle medication as taken/not taken
  const toggleMedicationTaken = (medicationId) => {
    if (!selectedDate) return;
    
    const dateKey = selectedDate.toISOString().split('T')[0];
    
    const updatedSchedule = {
      ...medicationSchedule
    };
    
    if (updatedSchedule[dateKey]) {
      updatedSchedule[dateKey] = updatedSchedule[dateKey].map(med => {
        if (med.id === medicationId) {
          return {
            ...med,
            taken: !med.taken
          };
        }
        return med;
      });
      
      setMedicationSchedule(updatedSchedule);
    }
  };

  // Select a date to view its scheduled medications
  const handleDateClick = (day) => {
    setSelectedDate(day.date);
    // Clear success/error messages when changing dates
    setSuccess('');
    setError('');
  };

  // Calculate adherence percentage for the current month
  const calculateAdherence = () => {
    const currentMonth = currentDate.getMonth();
    const currentYear = currentDate.getFullYear();
    
    let totalMedications = 0;
    let takenMedications = 0;
    
    Object.entries(medicationSchedule).forEach(([dateStr, meds]) => {
      const scheduleDate = new Date(dateStr);
      
      if (scheduleDate.getMonth() === currentMonth && scheduleDate.getFullYear() === currentYear) {
        meds.forEach(med => {
          totalMedications++;
          if (med.taken) takenMedications++;
        });
      }
    });
    
    if (totalMedications === 0) return 0;
    return Math.round((takenMedications / totalMedications) * 100);
  };

  // Get the month name
  const getMonthName = () => {
    return currentDate.toLocaleString('default', { month: 'long' });
  };

  // Get the weekday name
  const getWeekdayName = (date) => {
    return date.toLocaleString('default', { weekday: 'short' });
  };

  // Get scheduled medications for selected date
  const getScheduledMedications = () => {
    if (!selectedDate) return [];
    
    const dateKey = selectedDate.toISOString().split('T')[0];
    return medicationSchedule[dateKey] || [];
  };

  return (
    <div className={`medication-diary-container ${isSidebarOpen ? 'sidebar-open' : ''}`}>
      <div className="top-bar">
        <div className="top-center">
            <h1>Asthma Monitoring</h1>
        </div>
        <div className="nav-buttons">
          <button onClick={() => navigate('/profile')} className="profile-button">
            Profile
          </button>
          <button onClick={handleLogout} className="logout-button">
            Logout
          </button>
        </div>
      </div>

      <div className="content">
        <h2>Medication Diary</h2>
        
        {error && <div className="error-message">{error}</div>}
        {success && <div className="success-message">{success}</div>}
        
        <div className="adherence-stats">
          <div className="adherence-card">
            <h3>Monthly Adherence</h3>
            <div className="adherence-percentage">
              <span className="percentage-value">{calculateAdherence()}%</span>
              <span className="percentage-label">medications taken</span>
            </div>
          </div>
        </div>
        
        <div className="calendar-section">
          <div className="calendar-header">
            <button className="nav-button" onClick={previousMonth}>
              ← Previous
            </button>
            <h3>{getMonthName()} {currentDate.getFullYear()}</h3>
            <button className="nav-button" onClick={nextMonth}>
              Next →
            </button>
          </div>
          
          <div className="calendar-grid">
            <div className="calendar-weekdays">
              <div>Sun</div>
              <div>Mon</div>
              <div>Tue</div>
              <div>Wed</div>
              <div>Thu</div>
              <div>Fri</div>
              <div>Sat</div>
            </div>
            
            <div className="calendar-days">
              {generateCalendarDays().map((day, index) => (
                <div 
                  key={index} 
                  className={`calendar-day ${!day.isCurrentMonth ? 'other-month' : ''} 
                    ${selectedDate && day.date.toDateString() === selectedDate.toDateString() ? 'selected' : ''}
                    ${day.hasSchedule ? 'has-medications' : ''}`}
                  onClick={() => handleDateClick(day)}
                >
                  <span className="day-number">{day.date.getDate()}</span>
                  {day.hasSchedule && <div className="medication-indicator"></div>}
                </div>
              ))}
            </div>
          </div>
        </div>
        
        {selectedDate && (
          <div className="schedule-view">
            <div className="schedule-header">
              <h3>
                Medication Schedule for {selectedDate.toLocaleDateString('en-US', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' })}
              </h3>
              <button className="add-medication-button" onClick={() => openAddMedicationModal(selectedDate)}>
                Add Medication
              </button>
            </div>
            
            <div className="schedule-content">
              {getScheduledMedications().length > 0 ? (
                <div className="medications-list">
                  {getScheduledMedications().map((medication) => (
                    <div key={medication.id} className={`medication-item ${medication.taken ? 'taken' : 'not-taken'}`}>
                      <div className="medication-info">
                        <h4>{medication.name}</h4>
                        <div className="medication-details">
                          <span className="medication-dose">{medication.dose}</span>
                          <span className="medication-time">
                            {medication.time_slot === 'morning' ? '🌅 Morning' : 
                             medication.time_slot === 'afternoon' ? '☀️ Afternoon' : '🌙 Evening'}
                          </span>
                        </div>
                        {medication.comment && <p className="medication-comment">{medication.comment}</p>}
                      </div>
                      
                      <div className="medication-actions">
                        <button 
                          className={`taken-button ${medication.taken ? 'taken' : ''}`}
                          onClick={() => toggleMedicationTaken(medication.id)}
                        >
                          {medication.taken ? 'Taken ✓' : 'Mark as Taken'}
                        </button>
                        <button className="edit-button" onClick={() => openEditMedicationModal(medication)}>
                          Edit
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="no-medications">
                  <p>No medications scheduled for this day.</p>
                  <p>Click 'Add Medication' to schedule a medication.</p>
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {/* Add/Edit Medication Modal */}
      {isModalOpen && (
        <div className="modal-overlay">
          <div className="medication-modal">
            <div className="modal-header">
              <h3>{modalMode === 'add' ? 'Add New Medication' : 'Edit Medication'}</h3>
              <button className="close-modal" onClick={closeModal}>×</button>
            </div>
            
            <form onSubmit={handleSubmitMedication}>
              <div className="form-group">
                <label>Medication</label>
                <select 
                  name="medication_id"
                  value={formData.medication_id}
                  onChange={handleInputChange}
                  required
                >
                  <option value="">Select a medication</option>
                  {medications.map(med => (
                    <option key={med.id} value={med.id}>
                      {med.name} ({med.type})
                    </option>
                  ))}
                </select>
              </div>
              
              <div className="form-group">
                <label>Dose</label>
                <input 
                  type="text"
                  name="dose"
                  value={formData.dose}
                  onChange={handleInputChange}
                  placeholder="e.g. 100 mcg, 10 mg"
                  required
                />
              </div>
              
              <div className="form-group">
                <label>Time of Day</label>
                <select 
                  name="time_slot"
                  value={formData.time_slot}
                  onChange={handleInputChange}
                >
                  <option value="morning">Morning</option>
                  <option value="afternoon">Afternoon</option>
                  <option value="evening">Evening</option>
                </select>
              </div>
              
              <div className="form-group">
                <label>Comments (Optional)</label>
                <textarea 
                  name="comment"
                  value={formData.comment}
                  onChange={handleInputChange}
                  placeholder="Add any notes or special instructions"
                ></textarea>
              </div>
              
              <div className="modal-actions">
                <button type="button" className="cancel-button" onClick={closeModal}>
                  Cancel
                </button>
                <button type="submit" className="save-button">
                  {modalMode === 'add' ? 'Add to Schedule' : 'Update Schedule'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      <div className={`sidebar ${isSidebarOpen ? 'open' : ''}`}>
        <div className="sidebar-header">
         <h2>Menu</h2>
        </div>
        <nav className="sidebar-nav">
          <button onClick={() => navigate('/dashboard')}>
            Home
          </button>
          <button onClick={() => navigate('/recording-indicators')}>
            Recording Indicators
          </button>
          <button onClick={() => navigate('/exacerbation-forecast')}>
            Exacerbation Forecast
          </button>
          <button onClick={() => navigate('/graphs-of-changes')}>
            Graphs of Changes
          </button>
          <button onClick={() => navigate('/medication-diary')}>
            Medication Diary
          </button>
        </nav>
      </div>
      <div className="floating-menu-button" onClick={toggleSidebar}>
        <span></span>
        <span></span>
        <span></span>
      </div>
    </div>
  );
}

export default MedicationDiary;
